export function SubmitButton({name, children}){
    // console.log(name)
    return (
        <p type="submitButton">{name + children}</p>
    )
}

export function OptionButton(props){
    return (
        <Button {...props} type="optionButton"></Button>
    )
}


function Button(props){
    let style = "btn " + props.type;
    return (
        <button className={style} onClick={() => {props.onQuizName(props.children)}}>{props.children}</button>
    )
}

export function QuizThemeContent({name}){
    let path = (name) => {
        if(name == "html") return <path fill="#FF7E35" d="M24.508 7.607a1.25 1.25 0 0 1 .634 1.65l-10 22.5a1.25 1.25 0 1 1-2.284-1.015l10-22.5a1.251 1.251 0 0 1 1.65-.635ZM10.832 13.44a1.249 1.249 0 0 1 .1 1.765L6.674 20l4.263 4.795a1.25 1.25 0 1 1-1.87 1.66l-5-5.625a1.25 1.25 0 0 1 0-1.66l5-5.625a1.25 1.25 0 0 1 1.764-.105Zm18.337 0a1.25 1.25 0 0 1 1.765.105l5 5.625a1.25 1.25 0 0 1 0 1.66l-5 5.625a1.25 1.25 0 1 1-1.87-1.66L33.327 20l-4.262-4.795a1.25 1.25 0 0 1 .105-1.765Z"/>
    }
    return(
        <div className="content">
            <div className="svgContainer">
                <svg viewBox="0 0 40 40">path(name)</svg>
            </div>
            <p>{name}</p>
        </div>
    )
}
